#[derive(Debug)]
struct Child<T> {
    id: T,
    children: Vec<usize>,
}

impl<T> Child<T> {
    fn new(id: T) -> Self {
        Child {
            id,
            children: vec![],
        }
    }
}

#[derive(Debug)]
pub(crate) struct ChildGraph<T>(Vec<Child<T>>);

impl<T> ChildGraph<T>
where
    T: Sized + PartialEq + Clone,
{
    pub(crate) fn with_capacity(s: usize) -> Self {
        ChildGraph(Vec::with_capacity(s))
    }

    pub(crate) fn insert(&mut self, req: T) -> usize {
        self.0.iter().position(|e| e.id == req).unwrap_or_else(|| {
            let idx = self.0.len();
            self.0.push(Child::new(req));
            idx
        })
    }

    pub(crate) fn insert_child(&mut self, parent: usize, child: T) -> usize {
        let c_idx = self.0.len();
        self.0.push(Child::new(child));
        self.0[parent].children.push(c_idx);
        c_idx
    }

    pub(crate) fn iter(&self) -> impl Iterator<Item = &T> {
        self.0.iter().map(|r| &r.id)
    }

    pub(crate) fn contains(&self, req: &T) -> bool {
        self.0.iter().any(|r| r.id == *req)
    }
}

use bus::Bus;

mod message;

const MESSAGES: usize = 5_000_000;

fn seq(cap: usize) {
    let mut tx = Bus::new(cap);
    let mut rx = tx.add_rx();

    for i in 0..MESSAGES {
        tx.broadcast(message::new(i));
    }

    for _ in 0..MESSAGES {
        rx.recv().unwrap();
    }
}

fn spsc(cap: usize) {
    let mut tx = Bus::new(cap);
    let mut rx = tx.add_rx();

    crossbeam::scope(|scope| {
        scope.spawn(|_| {
            for i in 0..MESSAGES {
                tx.broadcast(message::new(i));
            }
        });

        for _ in 0..MESSAGES {
            rx.recv().unwrap();
        }
    })
    .unwrap();
}

fn main() {
    macro_rules! run {
        ($name:expr, $f:expr) => {
            let now = ::std::time::Instant::now();
            $f;
            let elapsed = now.elapsed();
            println!(
                "{:25} {:15} {:7.3} sec",
                $name,
                "Rust bus",
                elapsed.as_secs() as f64 + elapsed.subsec_nanos() as f64 / 1e9
            );
        };
    }

    run!("bounded1_spsc", spsc(1));

    run!("bounded_seq", seq(MESSAGES));
    run!("bounded_spsc", spsc(MESSAGES));
}

const USAGE: &str = "
Usage: noop [--sleep N] [--iters N]

Noop loop to measure CPU usage. See rayon-rs/rayon#642.

Options:
    --sleep N       How long to sleep (in millis) between doing a spawn. [default: 10]
    --iters N        Total time to execution (in millis). [default: 100]
";

use crate::cpu_time;
use docopt::Docopt;

#[derive(serde::Deserialize)]
pub struct Args {
    flag_sleep: u64,
    flag_iters: u64,
}

pub fn main(args: &[String]) {
    let args: Args = Docopt::new(USAGE)
        .and_then(|d| d.argv(args).deserialize())
        .unwrap_or_else(|e| e.exit());

    let m = cpu_time::measure_cpu(|| {
        for _ in 1..args.flag_iters {
            std::thread::sleep(std::time::Duration::from_millis(args.flag_sleep));
            rayon::spawn(move || {});
        }
    });
    println!(
        "noop --iters={} --sleep={}",
        args.flag_iters, args.flag_sleep
    );
    cpu_time::print_time(m);
}

use std::mem::MaybeUninit;
use winapi::um::processthreadsapi::{GetCurrentProcess, GetProcessTimes};

pub fn get_cpu_time() -> Option<u64> {
    let (kernel, user) = unsafe {
        let process = GetCurrentProcess();
        let mut _creation = MaybeUninit::uninit();
        let mut _exit = MaybeUninit::uninit();
        let mut kernel = MaybeUninit::uninit();
        let mut user = MaybeUninit::uninit();
        if GetProcessTimes(
            process,
            _creation.as_mut_ptr(),
            _exit.as_mut_ptr(),
            kernel.as_mut_ptr(),
            user.as_mut_ptr(),
        ) == 0
        {
            return None;
        }
        (kernel.assume_init(), user.assume_init())
    };
    let kernel = (kernel.dwHighDateTime as u64) << 32 | kernel.dwLowDateTime as u64;
    let user = (user.dwHighDateTime as u64) << 32 | user.dwLowDateTime as u64;
    Some(100 * (kernel + user))
}

use unicode_ident::{is_xid_continue, is_xid_start};

pub(crate) fn is_feature_name(s: &str) -> bool {
    s.chars()
        .all(|ch| is_xid_continue(ch) || matches!(ch, '-' | '+' | '.'))
}

pub(crate) fn is_ident(s: &str) -> bool {
    let mut cs = s.chars();
    cs.next()
        .is_some_and(|ch| is_xid_start(ch) || matches!(ch, '_'))
        && cs.all(is_xid_continue)
}

pub(crate) fn is_ascii_ident(s: &str) -> bool {
    let mut cs = s.chars();
    cs.next()
        .is_some_and(|ch| ch.is_ascii_alphabetic() || matches!(ch, '_'))
        && cs.all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '_'))
}

pub(crate) fn is_crate_name(s: &str) -> bool {
    let mut cs = s.chars();
    cs.next()
        .is_some_and(|ch| is_xid_start(ch) || matches!(ch, '-' | '_'))
        && cs.all(|ch| is_xid_continue(ch) || matches!(ch, '-'))
}

