#[stable(feature = "alloc_system_type", since = "1.28.0")]
unsafe impl GlobalAlloc for System {
    #[inline]
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        let size = layout.size();
        let align = layout.align();
        unsafe { hermit_abi::malloc(size, align) }
    }

    #[inline]
    unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
        let size = layout.size();
        let align = layout.align();
        unsafe {
            hermit_abi::free(ptr, size, align);
        }
    }

    #[inline]
    unsafe fn realloc(&self, ptr: *mut u8, layout: Layout, new_size: usize) -> *mut u8 {
        let size = layout.size();
        let align = layout.align();
        unsafe { hermit_abi::realloc(ptr, size, align, new_size) }
    }
}

use std::path::Path;

fn main() {
    let dir = Path::new(env!("CARGO_MANIFEST_DIR"));
    let root = dir.parent().unwrap();
    eprintln!("root: {}", root.display());
    walk(&root.join("core_arch/src/x86"));
    walk(&root.join("core_arch/src/x86_64"));
    walk(&root.join("core_arch/src/arm"));
    walk(&root.join("core_arch/src/aarch64"));
}

fn walk(root: &Path) {
    for file in root.read_dir().unwrap() {
        eprintln!("root: {}", root.display());
        let file = file.unwrap();
        if file.file_type().unwrap().is_dir() {
            walk(&file.path());
            continue;
        }
        let path = file.path();
        if path.extension().and_then(|s| s.to_str()) != Some("rs") {
            continue;
        }

        println!("cargo:rerun-if-changed={}", path.display());
    }
}

